  bloom += sampleBright(uv + vec2(-texel.x, 0.0)) * 0.1;
  bloom += sampleBright(uv + vec2(0.0,  texel.y)) * 0.1;
  bloom += sampleBright(uv + vec2(0.0, -texel.y)) * 0.1;

