  bloom += sampleBright(uv + vec2(-texel.x,  texel.y)) * 0.06;
  bloom += sampleBright(uv + vec2( texel.x, -texel.y)) * 0.06;
  bloom += sampleBright(uv + vec2(-texel.x, -texel.y)) * 0.06;

